#include <bits/stdc++.h>
using namespace std;
#define pii pair<int,int>
#define int long long
const int maxn=1e4+5;
struct node {
	vector<pii>e;
	int b,d=INT_MAX,cs;
} v[maxn];
queue<int> q;
bool flag=1;
int n,m;
void cheek(int id,int dis) {
	if(dis<v[id].d) {
		v[id].d=dis;
		if(!v[id].b) {
			v[id].b=1;
			q.push(id);
			flag&=(++v[id].cs<=n);
		}
	}
}
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>m;
	for(int i=1,x,y,z;i<=m;i++){
		cin>>x>>y>>z;
		v[y].e.emplace_back(x,z);
	}
	for(int i=1;i<=m;i++){
		cheek(i,0);
	}
	while(q.size()&&flag){
		auto p=q.front();q.pop();
		v[p].b=0;
		for(auto e:v[p].e){
			cheek(e.first,e.second+v[p].d);
		}
	}
	if(!flag){
		cout<<"NO";
	}else {
		for(int i=1;i<=n;i++){
			cout<<v[i].d<<" ";
		}
	}
	return 0;
}
